-- Mass enrollment sync:
-- Enroll active students into all active classes assigned to their section and academic year.
-- Skip existing enrollment rows, then refresh enrolled_count per class.
  `student_id`,
  `class_id`,
  `section_enrollment_id`,
  `enrollment_date`,
  `status`,
  `midterm_grade`,
  `final_grade`,
  `remarks`,
  `created_at`,
  `updated_at`
)
SELECT
  s.`id` AS `student_id`,
  c.`id` AS `class_id`,
  (
    SELECT se.`id`
    FROM `section_enrollments` se
    WHERE se.`student_id` = s.`id`
      AND se.`section_id` = s.`section_id`
      AND se.`academic_year_id` = s.`academic_year_id`
      AND se.`status` = 'enrolled'
    ORDER BY se.`id` DESC
    LIMIT 1
  ) AS `section_enrollment_id`,
  CURDATE() AS `enrollment_date`,
  'enrolled' AS `status`,
  NULL AS `midterm_grade`,
  NULL AS `final_grade`,
  'Mass enrollment sync' AS `remarks`,
  NOW() AS `created_at`,
  NOW() AS `updated_at`
FROM `students` s
JOIN `classes` c
  ON c.`section_id` = s.`section_id`
 AND c.`academic_year_id` = s.`academic_year_id`
 AND c.`status` = 'active'
LEFT JOIN `enrollments` e
  ON e.`student_id` = s.`id`
 AND e.`class_id` = c.`id`
 AND e.`status` IN ('enrolled', 'completed')
WHERE s.`section_id` IS NOT NULL
  AND s.`account_status` = 'active'
  AND e.`id` IS NULL;

UPDATE `classes` c
SET c.`enrolled_count` = (
  SELECT COUNT(*)
  FROM `enrollments` e
  WHERE e.`class_id` = c.`id`
    AND e.`status` = 'enrolled'
);

UPDATE `students` s
SET s.`enrollment_status` = 'enrolled'
WHERE EXISTS (
  SELECT 1
  FROM `enrollments` e
  WHERE e.`student_id` = s.`id`
    AND e.`status` = 'enrolled'
);

